package com.example.network

import okhttp3.Interceptor
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.Response
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET
import retrofit2.http.Headers

object NetworkModule {

    private const val DEV_BASE_URL = "https://dev.api.example.com/"
    private const val STAGING_BASE_URL = "https://staging.api.example.com/"
    private const val PROD_BASE_URL = "https://api.example.com/"

    private var environment: Environment = Environment.PRODUCTION

    enum class Environment {
        DEVELOPMENT, STAGING, PRODUCTION
    }

    fun setEnvironment(env: Environment) {
        environment = env
    }

    private fun getBaseUrl(): String {
        return when (environment) {
            Environment.DEVELOPMENT -> DEV_BASE_URL
            Environment.STAGING -> STAGING_BASE_URL
            Environment.PRODUCTION -> PROD_BASE_URL
        }
    }

    private val authInterceptor = Interceptor { chain ->
        val original: Request = chain.request()
        val request: Request = original.newBuilder()
            .header("Authorization", "Bearer YOUR_AUTH_TOKEN")
            .build()
        chain.proceed(request)
    }

    private val client: OkHttpClient = OkHttpClient.Builder()
        .addInterceptor(authInterceptor)
        .build()

    private val retrofit: Retrofit = Retrofit.Builder()
        .baseUrl(getBaseUrl())
        .client(client)
        .addConverterFactory(GsonConverterFactory.create())
        .build()

    val apiService: ApiService = retrofit.create(ApiService::class.java)
}

interface ApiService {
    @GET("users")
    @Headers("Accept: application/json")
    suspend fun getUserProfiles(): List<UserProfile>
}

